"""
mkt-christ commentary — Psalms 62–67
Run: python3 scripts/zc-christ-psalms-62-67.py

Key NT connections:
  Ps62:12  → Rom 2:6; Rev 22:12 (direct — renders according to works)
  Ps63:1   → John 6:35; 7:37 (shadow — soul thirsts / Christ satisfies)
  Ps65:2   → John 12:32 (direct — all flesh drawn to Christ)
  Ps66:6   → 1 Cor 10:1-2 (type — Exodus crossing as baptism)
  Ps67:1   → 2 Cor 4:6; Gal 3:14 (direct — Aaronic blessing in Christ)
  Ps67:3,5 → Rom 15:11 (direct — Paul cites for Gentile praise)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"62": {"1": "<p><span class=\"level\">shadow</span> <em>For God alone my soul waits in silence; from him comes my salvation.</em> Christ before Pilate embodies this silence: <em>he gave him no answer, not even to a single charge, so that the governor was greatly amazed</em> (Matt 27:14; cf. Isa 53:7). His salvation comes not from human defense but from God alone — the resurrection is God's single act of vindication for the one who waits in silent trust.</p>", "2": "<p><span class=\"level\">shadow</span> <em>He alone is my rock and my salvation, my fortress; I shall not be greatly shaken.</em> Christ is the rock — <em>the rock was Christ</em> (1 Cor 10:4). He is the one who shall not be shaken because God raised him: the resurrection is the ultimate steadying of the one whom death tried to shake. He who is the rock is also the one who rests on the rock in perfect trust.</p>", "3": "<p><span class=\"level\">shadow</span> <em>How long will all of you attack a man to batter him, like a leaning wall, a tottering fence?</em> The sustained assault on the righteous man — from the Sanhedrin's arrest through Pilate's interrogation and the mockery at the cross — batters the one who appears like a tottering fence. Yet he is the cornerstone (Eph 2:20) who cannot ultimately fall, however violently he is struck.</p>", "4": "<p><span class=\"level\">shadow</span> <em>They only plan to thrust him down from his high position. They take pleasure in falsehood. They bless with their mouths, but inwardly they curse.</em> The hypocrisy of those who hailed Jesus at the Triumphal Entry and then cried <em>crucify him!</em> five days later — blessing with mouths, cursing inwardly. Judas's kiss is the supreme instance: the gesture of friendship concealing betrayal.</p>", "5": "<p><span class=\"level\">shadow</span> <em>For God alone, O my soul, wait in silence, for my hope is from him.</em> Christ is himself the hope: <em>Christ in you, the hope of glory</em> (Col 1:27). The soul that waits in silence for God waits for the one who is God's ultimate answer. Christ modeled this waiting — in Gethsemane, <em>not my will, but yours, be done</em> (Luke 22:42) — and became the ground of all waiting hope.</p>", "6": "<p><span class=\"level\">shadow</span> <em>He only is my rock and my salvation, my fortress; I shall not be shaken.</em> The repeated refrain deepens with Christ's resurrection: the tomb could not hold him, the stone was rolled away (Matt 28:2), and the one who rested in the rock-hewn tomb was raised. He is unmoved by death itself — the fortress that no enemy can storm.</p>", "7": "<p><span class=\"level\">shadow</span> <em>On God rests my salvation and my glory; my mighty rock, my refuge is God.</em> Christ's glory rests on the Father's vindication through resurrection. He is simultaneously the one who takes refuge in God (as the righteous man) and the refuge itself (as the divine Son). Paul's <em>Christ, who is our life</em> (Col 3:4) and John's <em>I am the resurrection and the life</em> (John 11:25) both fulfill this verse.</p>", "8": "<p><span class=\"level\">theme</span> <em>Trust in him at all times, O people; pour out your heart before him; God is a refuge for us.</em> The invitation to pour out the heart before God is the posture of prayer Christ both exemplified and enables. He poured out his soul to death (Isa 53:12); through him we have access to the Father by one Spirit (Eph 2:18), so that we may pour out our hearts at all times.</p>", "9": "<p><span class=\"level\">theme</span> <em>Those of low estate are but a breath; those of high estate are a delusion; in the balances they go up; they are together lighter than a breath.</em> The vanity of human power — the Romans, the Sanhedrin, Pilate — all lighter than a breath against the purposes of God. Christ's kingdom cannot be shaken (Heb 12:28) while the empires that crucified him are dust. Human pretension is the backdrop against which divine power appears.</p>", "10": "<p><span class=\"level\">theme</span> <em>Put no trust in extortion; set no vain hopes on robbery; if riches increase, set not your heart on them.</em> Christ's teaching on wealth and the heart (Matt 6:19-21; Luke 12:15) echoes this wisdom. He himself had nowhere to lay his head (Matt 8:20), renouncing every form of material security to reveal the kingdom that no theft can diminish.</p>", "11": "<p><span class=\"level\">shadow</span> <em>Once God has spoken; twice have I heard this: that power belongs to God,</em> Divine power displayed supremely at the resurrection: <em>the power of God</em> (1 Cor 1:24) is Christ crucified and raised. The Father's power does not belong to Caesar or the Sanhedrin — it belongs to the one who raised Jesus from the dead and who will raise those who are in him (Rom 8:11).</p>", "12": "<p><span class=\"level\">direct</span> <em>and that to you, O Lord, belongs steadfast love. For you will render to a man according to his work.</em> Paul cites this verse in Romans 2:6 (rendering to each according to works) and Christ applies it to himself: <em>Behold, I am coming soon, bringing my recompense with me, to repay each one for what he has done</em> (Rev 22:12). The one who renders according to works is the risen Christ who holds the final judgment.</p>"}, "63": {"1": "<p><span class=\"level\">shadow</span> <em>O God, you are my God; earnestly I seek you; my soul thirsts for you; my flesh faints for you, as in a dry and weary land where there is no water.</em> Christ in the wilderness of temptation (Matt 4:1-11) inhabits this desert thirst — yet he is also the one who satisfies: <em>I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst</em> (John 6:35).</p>", "2": "<p><span class=\"level\">revelation of God</span> <em>So I have looked upon you in the sanctuary, beholding your power and glory.</em> The sanctuary where God's glory is seen is Christ himself: <em>we have seen his glory, glory as of the only Son from the Father, full of grace and truth</em> (John 1:14). The Transfiguration is the moment when disciples behold his power and glory in a foretaste of the resurrection (Matt 17:1-8).</p>", "3": "<p><span class=\"level\">shadow</span> <em>Because your steadfast love is better than life, my lips will praise you.</em> For Christ, the Father's steadfast love was literally valued above his own life: <em>I lay down my life</em> (John 10:17-18). Paul's echo — <em>to live is Christ, and to die is gain</em> (Phil 1:21) — reflects the same calculus. The one who counts love better than life gives his life freely and is raised.</p>", "4": "<p><span class=\"level\">shadow</span> <em>So I will bless you as long as I live; in your name I will lift up my hands.</em> Christ's lifted hands at his Ascension: <em>lifting up his hands he blessed them. While he blessed them, he parted from them and was carried up into heaven</em> (Luke 24:50-51). The blessing with lifted hands is his final gesture — the one who praised the Father through his life blesses his people as he departs.</p>", "5": "<p><span class=\"level\">shadow</span> <em>My soul will be satisfied as with fat and rich food, and my mouth will praise you with joyful lips,</em> The rich satisfaction of communion with God is realized in the Eucharist — the feast Christ provides where souls are satisfied (John 6:55-58). His mouth praised the Father even at the Last Supper (Matt 26:30 — <em>when they had sung a hymn, they went out</em>) and from the cross (Luke 23:46).</p>", "6": "<p><span class=\"level\">shadow</span> <em>when I remember you upon my bed, and meditate on you in the watches of the night;</em> Christ's night prayers — <em>in these days he went out to the mountain to pray, and all night he continued in prayer to God</em> (Luke 6:12). Gethsemane is the supreme night watch: the Son meditates on the Father through the darkest hours before the Passion.</p>", "7": "<p><span class=\"level\">shadow</span> <em>for you have been my help, and in the shadow of your wings I will sing for joy.</em> The shadow of God's wings as shelter: Christ applies this to Jerusalem — <em>How often would I have gathered your children together as a hen gathers her brood under her wings</em> (Matt 23:37). He longs to be the shelter his people refuse; yet for those who accept him, he is the wing-shadow of the Father's protection.</p>", "8": "<p><span class=\"level\">shadow</span> <em>My soul clings to you; your right hand upholds me.</em> Christ's intimate clinging to the Father through the Passion: <em>Father, into your hands I commit my spirit</em> (Luke 23:46). The right hand that upholds is the one that raises — <em>God exalted him at his right hand</em> (Acts 5:31). Upheld through death, he is set at the right hand of the Majesty on high.</p>", "9": "<p><span class=\"level\">shadow</span> <em>But those who seek to destroy my life shall go down into the depths of the earth;</em> Those who sought Christ's life — Herod (Matt 2), the Sanhedrin (Matt 26), Judas (Matt 26:47-50) — face the depths they intended for him. Christ himself descended into the depths of death (Eph 4:9 — <em>he also descended into the lower regions</em>) and rose; his enemies have no such resurrection.</p>", "10": "<p><span class=\"level\">shadow</span> <em>they shall be given over to the power of the sword; they shall be a portion for jackals.</em> The judgment reserved for those who destroyed the righteous one — Judas (Acts 1:18-19, dying in the field of blood) and Jerusalem (destroyed in AD 70 as Jesus predicted in Matt 24). The one delivered to the sword rose; those who wielded it suffer the consequences.</p>", "11": "<p><span class=\"level\">shadow</span> <em>But the king shall rejoice in God; all who swear by him shall exult, for the mouths of liars will be stopped.</em> The king who rejoices is the risen Christ: <em>for the joy that was set before him he endured the cross, despising the shame</em> (Heb 12:2). The mouths of liars — the false witnesses at the trial (Matt 26:59-61) — are stopped by the resurrection, which exposes every false accusation as void.</p>"}, "64": {"1": "<p><span class=\"level\">shadow</span> <em>Hear my voice, O God, in my complaint; preserve my life from dread of the enemy.</em> God hears Christ's voice in the complaint of Gethsemane — <em>with loud cries and tears, to him who was able to save him from death, and he was heard</em> (Heb 5:7). The preservation of his life comes not by averting death but by raising him through it.</p>", "2": "<p><span class=\"level\">shadow</span> <em>Hide me from the secret plots of the wicked, from the throng of evildoers,</em> The Sanhedrin's secret conspiracy: <em>the chief priests and the scribes were seeking how to put him to death, for they feared the people</em> (Luke 22:2). Their secret plot against Christ is the supreme instance of this verse — the righteous one surrounded by hidden conspirators.</p>", "3": "<p><span class=\"level\">shadow</span> <em>who whet their tongues like swords, who aim bitter words like arrows,</em> The verbal weapons at the trial: false witnesses (Matt 26:59-61), the high priest's accusations (Matt 26:65), the soldiers' taunts (Luke 23:36), the crowd's mockery (Matt 27:39-43). Tongues sharpened like swords are aimed at the one who is the Word of God — the living Word against whom words are weaponized.</p>", "4": "<p><span class=\"level\">shadow</span> <em>shooting from ambush at the blameless, shooting at him suddenly and without fear.</em> The arrest in Gethsemane is the ambush — Judas and the crowd arriving suddenly in the night (John 18:3). The blameless one is struck without warning by those who have no fear of God before their eyes (Rom 3:18, citing Ps 36:1). The ambush of the Son of God is the ultimate crime of the age.</p>", "5": "<p><span class=\"level\">shadow</span> <em>They hold fast to their evil purpose; they talk of laying snares secretly, thinking, Who can see us?</em> <em>Who can see us?</em> — they do not reckon with the one who sees in secret (Matt 6:4) and before whom all things are naked and exposed (Heb 4:13). The Sanhedrin thought their night trial and secret burial sealed would go unwitnessed by God — but the resurrection reveals all.</p>", "6": "<p><span class=\"level\">shadow</span> <em>They search out injustice, saying, We have accomplished a diligent search. For the inward thought and heart of a man is deep.</em> The deep inward scheming of those who plotted against Christ — their careful search for a legal pretext (Luke 22:2), the false witnesses sought (Matt 26:59). They thought they had accomplished their purpose; the resurrection overturns every deep scheme they devised.</p>", "7": "<p><span class=\"level\">shadow</span> <em>But God shoots his arrow at them; they are wounded suddenly.</em> The divine reversal at the resurrection: those who shot arrows at the blameless are suddenly wounded by God's own action. The stone rolled away, the guards trembling like dead men (Matt 28:4), the reports of resurrection spreading despite sealed tombs — God shoots his arrow, and the plotters are undone.</p>", "8": "<p><span class=\"level\">shadow</span> <em>They are brought to ruin, with their own tongues turned against them; all who see them will wag their heads.</em> The self-defeating plots of the Passion: Judas hangs himself (Matt 27:5); Pilate's inscription <em>King of the Jews</em> remains unchanged despite priestly objection (John 19:21-22); the sealed tomb is broken open. Their own measures turn against them and vindicate the one they condemned.</p>", "9": "<p><span class=\"level\">shadow</span> <em>Then all mankind fears; they tell what God has brought about and ponder what he has done.</em> The centurion's response at the cross: <em>Truly this was the Son of God!</em> (Matt 27:54). The fear that falls on all — the guards, the women, the disciples at the empty tomb — is the fear of beholding what God has brought about. The pondering of God's deeds is the first movement of Christian proclamation.</p>", "10": "<p><span class=\"level\">shadow</span> <em>Let the righteous one rejoice in the LORD and take refuge in him! Let all the upright in heart exult!</em> The righteous one who rejoices is Christ — raised from the dead, <em>the firstfruits of those who have fallen asleep</em> (1 Cor 15:20). All the upright in heart exult because his resurrection is their own: <em>if the Spirit of him who raised Jesus from the dead dwells in you</em> (Rom 8:11), the same exultation is theirs.</p>"}, "65": {"1": "<p><span class=\"level\">shadow</span> <em>Praise is due to you, O God, in Zion; and to you shall vows be performed.</em> The praise due in Zion is the praise of the church gathered around the risen Christ. He is the one who performs the ultimate vow — the vow of the Servant who gives himself for the many (Isa 53:12). Through him all vows to God are fulfilled in the Yes of Christ (2 Cor 1:20).</p>", "2": "<p><span class=\"level\">direct</span> <em>O you who hear prayer, to you shall all flesh come.</em> Jesus applies this universal coming to himself: <em>And I, when I am lifted up from the earth, will draw all people to myself</em> (John 12:32). The one to whom all flesh comes is the crucified and risen Christ — the fulfillment of this verse's promise that prayer reaches the one who gathers all humanity.</p>", "3": "<p><span class=\"level\">shadow</span> <em>When iniquities prevail against me, you atone for our transgressions.</em> The atonement — <em>you atone for our transgressions</em> — is God's own act, accomplished through Christ: <em>God was in Christ reconciling the world to himself, not counting their trespasses against them</em> (2 Cor 5:19). Iniquity prevails against Christ on the cross; God atones through that very event.</p>", "4": "<p><span class=\"level\">shadow</span> <em>Blessed is the one you choose and bring near, to dwell in your courts!</em> The chosen one brought near is Christ — the elect Servant (Isa 42:1; 1 Pet 2:4): <em>he chose us in him before the foundation of the world</em> (Eph 1:4). Through Christ, believers too are brought near to dwell in God's courts (Eph 2:13 — <em>brought near by the blood of Christ</em>).</p>", "5": "<p><span class=\"level\">shadow</span> <em>By awesome deeds you answer us with righteousness, O God of our salvation, the hope of all the ends of the earth and of the farthest seas;</em> The hope of all the ends of the earth — <em>you will receive power when the Holy Spirit has come upon you, and you will be my witnesses... to the end of the earth</em> (Acts 1:8). Christ is the hope (Col 1:27) brought to the farthest seas by the missionary church empowered by the Spirit.</p>", "6": "<p><span class=\"level\">revelation of God</span> <em>the one who by his strength established the mountains, being girded with might;</em> The creator God whose might established the mountains is the one who, in Christ, says <em>I have overcome the world</em> (John 16:33). The same power that set the mountains in place raised Jesus from the dead — Paul identifies it as the same divine strength (Eph 1:19-20).</p>", "7": "<p><span class=\"level\">shadow</span> <em>who stills the roaring of the seas, the roaring of their waves, the tumult of the peoples,</em> Christ stills the storm: <em>he rebuked the wind and said to the sea, Peace! Be still! And the wind ceased, and there was a great calm</em> (Mark 4:39). The disciples asked, <em>Who then is this?</em> — the creator God who stills the seas is present in human flesh.</p>", "8": "<p><span class=\"level\">shadow</span> <em>so that those who dwell at the ends of the earth are in awe at your signs. You make the shouts of the morning and the evening ring out with joy.</em> The signs of Christ — healings, resurrections, the cross and empty tomb — inspire awe at the ends of the earth (Acts 4:16 — <em>a notable sign has been performed, and we cannot deny it</em>). The shouts of the morning ring out at the resurrection announcement.</p>", "9": "<p><span class=\"level\">shadow</span> <em>You visit the earth and water it; you greatly enrich it; the river of God is full of water.</em> Christ the living water visits the earth in the Incarnation. The river of God full of water is the Spirit poured out: <em>out of his heart will flow rivers of living water</em> (John 7:38-39 — <em>he said this about the Spirit</em>). The enrichment of the earth by Christ's coming and the Spirit's outpouring is the new covenant's abundance.</p>", "10": "<p><span class=\"level\">shadow</span> <em>You water its furrows abundantly, settling its ridges, softening it with showers, and blessing its growth.</em> The parable of the sower (Matt 13:1-23) — Christ the sower watering the earth with the word, seeking fruitful ground. The rain that softens soil is the word and Spirit working together to produce the harvest of the kingdom.</p>", "11": "<p><span class=\"level\">shadow</span> <em>You crown the year with your bounty; your wagon tracks overflow with abundance.</em> The abundance of the messianic age: the wedding at Cana (John 2:1-11 — 180 gallons of finest wine), the feeding of the 5,000 (twelve baskets left over), the feeding of the 4,000. Christ's presence crowns every moment with bounty — the overflowing abundance of the kingdom.</p>", "12": "<p><span class=\"level\">shadow</span> <em>The pastures of the wilderness overflow, the hills gird themselves with joy;</em> The wilderness restored: Isaiah's vision of the desert rejoicing (Isa 35:1) finds its fulfillment in Christ who makes the wilderness blossom — healing in deserted places (Matt 14:13-21), feeding crowds in the wilderness (Matt 15:32-38), transformed lives spreading joy through desolate regions.</p>", "13": "<p><span class=\"level\">shadow</span> <em>the meadows clothe themselves with flocks, the valleys deck themselves with grain, they shout and sing together for joy.</em> The eschatological harvest: Christ's parable of the harvest (Matt 13:39 — <em>the harvest is the end of the age</em>); the reaper's joy (John 4:35-36 — <em>the fields are white for harvest</em>). The whole creation's singing anticipates Paul's vision: <em>the creation itself will be set free from its bondage to corruption</em> (Rom 8:21).</p>"}, "66": {"1": "<p><span class=\"level\">shadow</span> <em>Shout for joy to God, all the earth;</em> The universal shout of joy directed at God reaches its fulfillment in the praise of the Lamb: <em>Worthy is the Lamb who was slain, to receive power and wealth and wisdom and might and honor and glory and blessing!</em> (Rev 5:12). All the earth's joy — the eschatological shout — is concentrated in the risen Christ.</p>", "2": "<p><span class=\"level\">shadow</span> <em>sing the glory of his name; give to him glorious praise!</em> The glorious name sung by all the earth is the name above every name (Phil 2:9-11). Paul commands: <em>in the name of the Lord Jesus, giving thanks to God the Father through him</em> (Col 3:17). The glorious praise is Christ-centered praise — the Father glorified in the Son.</p>", "3": "<p><span class=\"level\">shadow</span> <em>Say to God, How awesome are your deeds! So great is your power that your enemies come cringing to you.</em> The awesome deed of the cross and resurrection: enemies who come cringing — in Paul's framework, every power and principality prostrating before the name of Christ (Phil 2:10), and ultimately <em>he must reign until he has put all his enemies under his feet</em> (1 Cor 15:25).</p>", "4": "<p><span class=\"level\">shadow</span> <em>All the earth worships you and sings praises to you; they sing praises to your name.</em> The universal worship anticipated here is the worship of the Lamb in Revelation (Rev 5:13 — <em>every creature in heaven and on earth and under the earth and in the sea</em>). Christ is the one to whom all the earth's praise is ultimately directed (John 5:23 — <em>that all may honor the Son, just as they honor the Father</em>).</p>", "5": "<p><span class=\"level\">shadow</span> <em>Come and see what God has done: he is awesome in his deeds toward the children of man.</em> The angel's invitation: <em>Come, see the place where he lay</em> (Matt 28:6). The awesome deed toward humanity is the resurrection — the decisive act by which God demonstrates his power over death for all who trust in Christ (1 Cor 15:20-22).</p>", "6": "<p><span class=\"level\">type</span> <em>He turned the sea into dry land; they passed through the river on foot. There did we rejoice in him,</em> The Exodus crossing is a type of Christ: Paul identifies the sea-crossing as baptism — <em>all were baptized into Moses in the cloud and in the sea</em> (1 Cor 10:1-2). The crossing through water into freedom is the pattern Christ fulfills in baptism into his death and resurrection (Rom 6:3-4).</p>", "7": "<p><span class=\"level\">shadow</span> <em>who rules by his might forever, whose eyes keep watch on the nations — let not the rebellious exalt themselves.</em> Christ rules by might forever from the Father's right hand (Heb 1:3; 1 Cor 15:25). His eyes as Lord of the nations: <em>his eyes are like a flame of fire</em> (Rev 1:14; 2:18) — watching over the nations and addressing each church with divine authority.</p>", "8": "<p><span class=\"level\">theme</span> <em>Bless our God, O peoples; let the sound of his praise be heard,</em> The peoples blessing God in Christ: Paul's vision in Rom 15:9-11 of Gentiles glorifying God alongside Israel, citing multiple OT texts showing the universal praise of God. The sound of praise heard among all peoples is the church's mission — the worship of Christ spreading through every tongue.</p>", "9": "<p><span class=\"level\">shadow</span> <em>who has kept our soul among the living and has not let our feet slip.</em> Christ keeps those who are his among the living — <em>because I live, you also will live</em> (John 14:19). He who was kept by the Father through death (Acts 2:24 — God raised him up, loosing the pangs of death) now keeps his people so that their feet do not slip into permanent death.</p>", "10": "<p><span class=\"level\">shadow</span> <em>For you, O God, have tested us; you have tried us as silver is tried.</em> The testing of Christ in the wilderness (Matt 4:1-11), in Gethsemane, and on the cross: he is tried and emerges as refined silver — <em>a lamb without blemish or spot</em> (1 Pet 1:19). The testing of believers is patterned on his: <em>the testing of your faith... more precious than gold</em> (1 Pet 1:7).</p>", "11": "<p><span class=\"level\">shadow</span> <em>You brought us into the net; you laid a crushing burden on our backs;</em> The crushing burden: <em>Surely he has borne our griefs and carried our sorrows</em> (Isa 53:4). Christ takes the burden on himself — the yoke of the cross (Matt 11:28-30 contrasts his easy yoke with the crushing burden). He enters the net of suffering to carry what no one else can bear.</p>", "12": "<p><span class=\"level\">shadow</span> <em>you let men ride over our heads; we went through fire and through water; yet you have brought us out to a place of abundance.</em> Fire and water as trials — 1 Pet 1:7 (faith tested by fire); the place of abundance is the new creation. Christ himself went through the fire of judgment and the water of death to bring his people out to the resurrection abundance (2 Cor 4:17 — <em>an eternal weight of glory beyond all comparison</em>).</p>", "13": "<p><span class=\"level\">shadow</span> <em>I will come into your house with burnt offerings; I will perform my vows to you,</em> Christ is the ultimate burnt offering — <em>who through the eternal Spirit offered himself without blemish to God</em> (Heb 9:14). He performs the vow of the Servant (Isa 53:10 — <em>when his soul makes an offering for guilt</em>), entering the house of God not with animal sacrifice but with his own blood (Heb 9:12).</p>", "14": "<p><span class=\"level\">shadow</span> <em>that which my lips uttered and my mouth promised when I was in trouble.</em> The vow made in trouble — Gethsemane's <em>not my will, but yours, be done</em> (Luke 22:42) is the vow Christ keeps. He promised obedience to the Father through the cup of suffering and delivered it fully on the cross, the faithful keeper of every promise made in the hour of trouble.</p>", "15": "<p><span class=\"level\">shadow</span> <em>I will offer to you burnt offerings of fattened animals, with the smoke of the sacrifice of rams; I will make an offering of bulls and goats.</em> The sacrificial system this verse celebrates is fulfilled and ended in Christ: <em>it is impossible for the blood of bulls and goats to take away sins</em> (Heb 10:4). Christ's single offering perfects what the repeated offerings of rams and bulls could only shadow (Heb 10:10-14).</p>", "16": "<p><span class=\"level\">theme</span> <em>Come and hear, all you who fear God, and I will tell what he has done for my soul.</em> The personal testimony of what God has done is the shape of Christian witness: <em>what we have seen and heard we proclaim also to you</em> (1 John 1:3). Christ himself declares the Father's name to his brothers (Heb 2:12) — the testimony of what God has done for his soul is the resurrection proclamation.</p>", "17": "<p><span class=\"level\">shadow</span> <em>I cried to him with my mouth, and high praise was on my tongue.</em> Christ's cry to the Father from the cross (Matt 27:46; Luke 23:46) and the praise that followed — the resurrection doxology. He who cried in abandonment also cried in trust; both cries are heard; the praise on his tongue becomes the church's song (Heb 13:15).</p>", "18": "<p><span class=\"level\">shadow</span> <em>If I had cherished iniquity in my heart, the Lord would not have listened.</em> Christ cherished no iniquity — <em>which of you convicts me of sin?</em> (John 8:46); <em>in him there is no sin</em> (1 John 3:5). Therefore the Lord listened: Heb 5:7 — <em>he was heard because of his reverence.</em> His sinless heart is the ground of his efficacious prayer and perfect atonement.</p>", "19": "<p><span class=\"level\">shadow</span> <em>But truly God has listened; he has attended to the voice of my prayer.</em> God listened to Christ in Gethsemane — not by removing the cup but by sustaining him through it and raising him from the dead. The ultimate answer to Christ's prayer is the resurrection: God attended to the voice of his prayer and answered with the power that brings life from death (Heb 5:7).</p>", "20": "<p><span class=\"level\">revelation of God</span> <em>Blessed be God, because he has not rejected my prayer or removed his steadfast love from me!</em> The apparent rejection of the cross — <em>My God, why have you forsaken me?</em> — is overturned by this blessing: God did not ultimately reject his prayer or remove his steadfast love. The resurrection is the proof that divine love was present through every moment of the Passion, never withdrawn, always keeping (Rom 8:38-39).</p>"}, "67": {"1": "<p><span class=\"level\">direct</span> <em>May God be gracious to us and bless us and make his face to shine upon us,</em> The Aaronic blessing (Num 6:24-26) is fulfilled in Christ: the blessing of Abraham comes to the Gentiles through Christ Jesus (Gal 3:14). The face of God shining — <em>God who said let light shine out of darkness, has shone in our hearts to give the light of the knowledge of the glory of God in the face of Jesus Christ</em> (2 Cor 4:6). Christ is the shining face of God.</p>", "2": "<p><span class=\"level\">direct</span> <em>that your way may be known on earth, your saving power among all nations.</em> Christ declares: <em>I am the way, and the truth, and the life</em> (John 14:6). His saving power is proclaimed among all nations through the Great Commission (Matt 28:19-20). The way of God known on earth is the way of the cross and resurrection — the saving power that extends to every nation.</p>", "3": "<p><span class=\"level\">direct</span> <em>Let the peoples praise you, O God; let all the peoples praise you!</em> Paul quotes this verse in Romans 15:11 as part of his catena demonstrating that the Gentiles were always meant to glorify God alongside Israel: <em>Praise the Lord, all you Gentiles, and let all the peoples extol him.</em> The universal praise is the telos of Christ's mission — the nations brought in to glorify the God of Israel through Jesus Christ.</p>", "4": "<p><span class=\"level\">shadow</span> <em>Let the nations be glad and sing for joy, for you judge the peoples with equity and guide the nations upon earth.</em> The equitable judgment and guidance of the nations is vested in the risen Christ: <em>he has fixed a day on which he will judge the world in righteousness by a man whom he has appointed</em> (Acts 17:31). The nations' gladness is eschatological — the joy of receiving just governance from the one King.</p>", "5": "<p><span class=\"level\">direct</span> <em>Let the peoples praise you, O God; let all the peoples praise you!</em> The refrain repeated — the insistence of universal praise. Paul's citations in Rom 15:9-11 culminate in this missional vision: Christ has become a servant to the circumcised so that the Gentiles might glorify God (Rom 15:8-9). Every repetition of the refrain is a prayer that the Great Commission reaches its completion.</p>", "6": "<p><span class=\"level\">shadow</span> <em>The earth has yielded its increase; God, our God, shall bless us.</em> The earth's yield reaches its eschatological fullness in Christ the firstfruits (1 Cor 15:20,23): his resurrection is the first harvest of the new creation. The blessing God gives is the blessing of the Spirit poured out through Christ — the firstfruits of the Spirit (Rom 8:23) guaranteeing the full harvest to come.</p>", "7": "<p><span class=\"level\">shadow</span> <em>God shall bless us; let all the ends of the earth fear him!</em> The final verse completes the universalizing arc: the fear of the LORD spreading to all the ends of the earth. Acts 1:8 is the commission that drives this: <em>you will be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth.</em> God's blessing through Christ propels the church to the ends of the earth in holy reverence.</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
